// WITHOUT mocking: calls real API (slow, unreliable)
test('displays weather', async () => {
  const weather = await fetchWeather('NYC'); // Real API call!
  expect(weather.temp).toBeDefined();
});

// WITH mocking: fake the API response (fast, reliable)
test('displays weather', async () => {
  jest.spyOn(api, 'fetchWeather').mockResolvedValue({
    temp: 72, condition: 'sunny'
  });
  const weather = await fetchWeather('NYC'); // Returns fake data!
  expect(weather.temp).toBe(72);
});
